/**
 * Chain interaction via polkadot-api (PAPI).
 *
 * SETUP REQUIRED: Before using, generate PAPI descriptors:
 *   1. Start the node:  cd mental-poker-runtime && ./target/release/mental-poker-node --dev
 *   2. Generate types:  cd client && npx papi add -w ws://127.0.0.1:9944 mental-poker-runtime
 *
 * This creates .papi/descriptors/ with typed chain definitions.
 */

import { createClient, type PolkadotSigner, type PolkadotClient } from "polkadot-api";
import { getWsProvider } from "polkadot-api/ws-provider/web";
// Generated by `npx papi add`. Won't resolve until codegen is done.
// @ts-expect-error -- generated by papi add
import { mentalPokerRuntime } from "@polkadot-api/descriptors";

export type TypedApi = ReturnType<PolkadotClient["getTypedApi"]>;

export interface ChainConnection {
  client: PolkadotClient;
  api: TypedApi;
}

/** Connect to the Substrate node. */
export async function connect(
  wsUrl: string = "ws://127.0.0.1:9944",
): Promise<ChainConnection> {
  const provider = getWsProvider(wsUrl);
  const client = createClient(provider);
  const api = client.getTypedApi(mentalPokerRuntime);
  return { client, api };
}

/** Disconnect from the node. */
export function disconnect(conn: ChainConnection): void {
  conn.client.destroy();
}

// --- Extrinsic Helpers ---
// Each function submits a tx and waits for it to be included in a finalized block.

export async function createGame(
  api: TypedApi,
  signer: PolkadotSigner,
  deckSize: number,
  numPlayers: number,
): Promise<number> {
  const result = await (api as any).tx.MentalPoker.create_game({
    deck_size: deckSize,
    num_players: numPlayers,
  }).signAndSubmit(signer);

  // Extract game_id from GameCreated event
  for (const event of result.events) {
    if (
      event.type === "MentalPoker" &&
      event.value.type === "GameCreated"
    ) {
      return event.value.value.game_id;
    }
  }
  // Fallback: read GameCounter - 1
  const counter = await (api as any).query.MentalPoker.GameCounter.getValue();
  return counter - 1;
}

export async function registerPlayer(
  api: TypedApi,
  signer: PolkadotSigner,
  gameId: number,
  playerHelloBytes: Uint8Array,
): Promise<void> {
  await (api as any).tx.MentalPoker.register_player({
    game_id: gameId,
    player_hello_bytes: playerHelloBytes,
  }).signAndSubmit(signer);
}

