// --- Storage Queries ---

export async function readCurrentDeck(
  api: TypedApi,
  gameId: number,
): Promise<Uint8Array> {
  const raw = await (api as any).query.MentalPoker.CurrentDeck.getValue(gameId);
  return asBytes(raw);
}

export async function readAggregateKeyData(
  api: TypedApi,
  gameId: number,
): Promise<Uint8Array> {
  const raw = await (api as any).query.MentalPoker.AggregateKeyData.getValue(gameId);
  return asBytes(raw);
}

export async function readGameInfo(
  api: TypedApi,
  gameId: number,
): Promise<{ phase: string; deck_size: number; num_players: number; registered_count: number } | undefined> {
  return (api as any).query.MentalPoker.Games.getValue(gameId);
}

export async function readShuffleIndex(
  api: TypedApi,
  gameId: number,
): Promise<number> {
  return (api as any).query.MentalPoker.ShuffleIndex.getValue(gameId);
}

/** Convert PAPI's Binary/BoundedVec<u8> to Uint8Array. */
function asBytes(val: unknown): Uint8Array {
  if (val instanceof Uint8Array) return val;
  if (val && typeof val === "object" && "asBytes" in val) {
    return (val as { asBytes(): Uint8Array }).asBytes();
  }
  if (Array.isArray(val)) return new Uint8Array(val);
  throw new Error(`Cannot convert to bytes: ${typeof val}`);
}
